item.description:
Výber autentifikácie Zakomentovať alebo vybrať jeden správny spôsob autentifikácie v /etc/dovecot-conf.d/10-auth.conf
#!include auth-deny.conf.ext
#!include auth-master.conf.ext
#!include auth-oauth2.conf.ext
#!include auth-system.conf.ext
#!include auth-sql.conf.ext
#!include auth-ldap.conf.ext
#!include auth-passwdfile.conf.ext
!include auth-static.conf.ext\
Nastavenie autentifikácie Konfigurácia statického súbora /etc/dovecot-conf.d/conf.d/auth-static.conf.ext
auth_mechanisms = plain login
auth_allow_cleartext = no
passdb passwd-file {
passwd_file_path = /etc/dovecot/passdb
# passdb_default_password_scheme = SHA512-CRYPT
}
userdb static {
fields {
uid = vmail
gid = vmail
home = /var/vmail/%
mail_driver = maildir
mail_path = /var/vmail/%/Maildir # full mail location

Krátky návod ako nainštalovať DHCP server na Debian. Je potom už jednoduché dorobiť boot-ovanie po sieti cez PXE.
Inštalácia apt install isc-dhcp-server
Konfigurácia # option definitions common to all supported networks...
option domain-name &quot;fordo.sk&quot;;
option domain-name-servers ns1.example.org, ns2.example.org;
default-lease-time 600;
max-lease-time 7200;
# The ddns-updates-style parameter controls whether or not the server will
# attempt to do a DNS update when a lease is confirmed. We default to the
# behavior of the version 2 packages ('none', since DHCP v2 didn't

SELECT
table_name, owner FROM user_tables;
SELECT table_name, owner FROM all_tables ORDER BY owner, table_name;
select username from dba_users;
CREATE USER books_admin IDENTIFIED BY MyPassword;
GRANT CONNECT TO books_admin;
GRANT CONNECT, RESOURCE, DBA TO books_admin;
GRANT CREATE SESSION GRANT ANY PRIVILEGE TO books_admin;
GRANT UNLIMITED TABLESPACE TO books_admin;
SQL&gt; select USERNAME,ACCOUNT_STATUS from dba_users where ORACLE_MAINTAINED &lt;&gt; 'Y';
SQL&gt; select USERNAME,ACCOUNT_STATUS from dba_users where USERNAME like '%XM%';
SQL&gt; r
1* SELECT username, status, osuser, process, machine, terminal, logon_time FROM v$session where MACHINE &lt;&gt; 'hostname'

Pridáme skupinu
groupadd dsodb\
Vytvoríme užívateľov
useradd -g dsodb -m dsodb;
useradd -g db2fenc1 -m db2fenc1;
useradd -g db2inst1 -m db2inst1;
useradd -g srduser -m srduser;
useradd -g iauser -m iauser;
useradd -g xmetasr -m xmetasr;
useradd -g dsadm -m dsadm;
useradd -g xmeta -m xmeta;
useradd -g dsodb -m dsodb;\
Nainštalujeme balík nástrojov
yum groupinstall &quot;Development Tools&quot;\
Nainštalujeme knižnice
yum install -y libXp libXtst glibc libXp libXau libXext libX11 libxcb libXmu nss compat-libstdc* glibc libXp libXtst

Pridáme repozitáre:
echo &quot;deb http://ftp.cz.debian.org/debian/ stretch main non-free
deb-src http://ftp.cz.debian.org/debian/ stretch main non-free
deb http://security.debian.org/debian-security stretch/updates main contrib non-free
deb-src http://security.debian.org/debian-security stretch/updates main contrib non-free
# stretch-updates, previously known as 'volatile'
deb http://ftp.cz.debian.org/debian/ stretch-updates main contrib
deb-src http://ftp.cz.debian.org/debian/ stretch-updates main contrib
&quot; &gt; /etc/apt/sources.list
Nainštalujeme pár základných balíčkov
apt-get clean ;
apt update ;
apt install -y apt-utils ;
apt install -y dialog ;
apt install -y libterm-ui-perl ;
apt upgrade -y ;

Je niekoľko spôsobov ako to dosiahnuť. Pokiaľ máme nainštalovaný Linux ale spúšta sa nám iba priamo MS Windows, nabootujeme nejaku Live distribúciu z USB alebo cez CD/DVD-ROM. Osobne používam Ubuntu. Na verzi nezáleží, takže môžme použiť aj staršiu inštalačku, musíme však dodržať architektúru.
Po nabootovaní Linuxu otvoríme terminál a pripojime disk kde máme uz nainštalovaný Linux do &quot;/mnt&quot;.
sudo mount /dev/sda1 /mnt ;
Nabindujeme pár potrebných adresárov
sudo mount --bind /dev /mnt/dev ;

Toto je spôsob ako vytvoriť RAM drive. Dá sa to dobre automatizovať ked dáme tieto príkazy do skriptu, a skript dáme na spustenie po štarte systému.
Vytvorenie adresára:
mkdir /tmp/ramdisk ;
Nastavenie oprávnenia:
chmod 777 /tmp/ramdisk ;
Vytvorenie samotného RAM drive:
mount -t tmpfs -o size=10000M tmpfs /tmp/ramdisk/ ;

Zmažeme všetky nastavenia, na toto pozor, lebo to všetku komunikáciu zablokuje:
iptables -F;
Nastavíme všeobecné pravidlá, že sa všetka prichádzajúca komunikácia bude blokovať:
iptables -P FORWARD DROP;
iptables -P INPUT DROP;
iptables -P OUTPUT ACCEPT;
Pre povolenie prichádzajúcich paketov prijatých vytvorených spojení:
iptables -A INPUT -m state --state ESTABLISHED,RELATED -j ACCEPT
Povolenie všetkého na localhost-e:
iptables -A INPUT -s 127.0.0.0/8 -d 127.0.0.0/8 -i lo -j ACCEPT
Otvorenie samotného portu, napr. 22 pre SSH server, alebo 80 pre HTTP server:
